import{_ as n,L as a,c as p,o as r,aj as l,x as i}from"./chunks/framework.DXt7FdPx.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/磊科N60Pro安装ImmortalWrt教程.md","filePath":"blog/磊科N60Pro安装ImmortalWrt教程.md","lastUpdated":1780853682000}'),o={name:"blog/磊科N60Pro安装ImmortalWrt教程.md"};function h(c,s,d,m,b,g){const t=a("LastUpdated"),e=a("confetti");return r(),p("div",null,[s[0]||(s[0]=l(`<h3 id="开箱-官方固件" tabindex="-1"><strong>开箱＆官方固件</strong> <a class="header-anchor" href="#开箱-官方固件" aria-label="Permalink to &quot;**开箱＆官方固件**&quot;">​</a></h3><p>外包装和磊科N60一致，黄色的纸箱尺寸还挺大的，质感不错。</p><p><img src="https://pic4.zhimg.com/v2-faaf374703af417c0e6133c474da5591_1440w.jpg" alt=""> ▲ 12V/2A的电源、6类网线、说明书、路由器本体，有些人觉得造型很丑，我觉得还好，像飞碟。</p><p><img src="https://pica.zhimg.com/v2-63dabce8e939ec42c53a4f8a46114920_1440w.jpg" alt=""> ▲ 升级的USB3.0接口、WAN口和LAN1口是2.5G，其余3个LAN是1G，DC电源、电源开关键，独立开关机有个好处是，进入uboot的时候开关电源很方便，不需要来回插拔。</p><p><img src="https://pic2.zhimg.com/v2-84e1d97e1a778a1a56cf5f91f532c58d_1440w.jpg" alt=""> ▲ 官方固件后台首页UI、有网速显示，后台地址：192.168.0.1</p><p><img src="https://picx.zhimg.com/v2-69ee66025e7dfa54b357429c0ab20c5d_1440w.jpg" alt=""> ▲ 磊科不锁SSH，方便我们刷机</p><p><img src="https://pica.zhimg.com/v2-f26609029a3a4ccfed1dfc4e90e5f5c0_1440w.jpg" alt=""> ▲ 官方固件USB接口只能当做共享文件使用，开启SMB共享设置一下用户名和密码以及权限，保存即可生效</p><p><img src="https://pic3.zhimg.com/v2-87c62dcdfcadec891994fd504b064406_1440w.jpg" alt=""> ▲ 路由器USB接口插入了固态硬盘、使用Win系统拖动文件，读取速度43MB/秒，写入速度47MB/秒；这个读写速度比较一般，有提升空间。</p><p>其他没什么看的了，官方固件功能有限，不支持端口聚合、自定义网口、USB上网、USB共享打印机等功能，无法发挥出硬件的实力，我们下面进入刷机OpenWrt环节。</p><h3 id="备份官方固件" tabindex="-1"><strong>备份官方固件</strong> <a class="header-anchor" href="#备份官方固件" aria-label="Permalink to &quot;**备份官方固件**&quot;">​</a></h3><p>刷机之前最好是备份一下系统分区，万一出故障后方便恢复官方系统。</p><p>使用SSH工具（推荐<code>MobaXter</code>）连接路由器（192.168.0.1），用户名：useradmin 密码：管理密码，注意用户名不是root</p><p><img src="https://pic1.zhimg.com/v2-5bb9307776dd26519725e216aa3a49b8_1440w.jpg" alt=""> ▲ 官方系统是基于Linux5.4.246内核，OpenWrt版本21.02，有5个分区，Factory 校准分区存储了MAC地址、无线射频校准参数、EEPROM等信息，每台机器都不同，必须备份。</p><p>输入下面代码、回车进行备份：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 备份 BL2 引导分区（mtd1）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/mtd1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/tmp/mtd1_BL2.bin</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 备份 u-boot-env 环境变量（mtd2）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/mtd2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/tmp/mtd2_ubootenv.bin</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 备份 Factory 校准分区（mtd3，必选！）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/mtd3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/tmp/mtd3_Factory.bin</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 备份 ubi 系统固件（mtd5）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=/dev/mtd5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/tmp/mtd5_ubi.bin</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><img src="https://picx.zhimg.com/v2-e6d758efa10281a8f530cef8fb0f0f83_1440w.jpg" alt=""> ▲ 使用Winscp工具或者MobaXter到tmp目录下载刚备份的4个文件到电脑保存备用</p><h3 id="刷入uboot" tabindex="-1"><strong>刷入Uboot</strong> <a class="header-anchor" href="#刷入uboot" aria-label="Permalink to &quot;**刷入Uboot**&quot;">​</a></h3><p>U-Boot源自 hanwckf/bl-mt798x项目，由1715173329大佬制作，支持DHCP下发IP地址，无需手动配置 IP 地址。</p><blockquote><p>Uboot地址：<a href="https://drive.wrt.moe/uboot/mediatek" target="_blank" rel="noreferrer">https://drive.wrt.moe/uboot/mediatek</a></p></blockquote><p><strong>磊科N60PRO刷机资料包：</strong></p><p><strong>链接：<a href="https://pan.quark.cn/s/60389c4bbdc2" target="_blank" rel="noreferrer">https://pan.quark.cn/s/60389c4bbdc2</a></strong></p><p><strong>提取码：Qryi</strong></p><p><img src="https://pic4.zhimg.com/v2-4a8b53a050f876679a7d4066b9172b91_1440w.jpg" alt=""></p><p>下载<code>mt7986-netcore_n60-pro-fip.bin</code>文件，将下载好的uboot传到/tmp 目录下，运行下面代码：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mtd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/mt7986-netcore_n60-pro-fip.bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FIP</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="https://pic4.zhimg.com/v2-aa7c81ee0fdbd6881eead61d0b0ceba1_1440w.jpg" alt=""> ▲ 如图显示则uboot刷入成功</p><p><strong>然后路由器断电、把网线插入千兆LAN口接入电脑，</strong></p><p><img src="https://pic2.zhimg.com/v2-221071795db70d515ab645a96e4e5d53_1440w.jpg" alt=""> ▲ 使用顶针按住机身底部的Reset按键不动再接通电、8s后电源灯变成蓝灯慢闪进入uboot模式了，再松开。</p><h3 id="刷入大功率immortalwrt固件" tabindex="-1"><strong>刷入大功率immortalwrt固件</strong> <a class="header-anchor" href="#刷入大功率immortalwrt固件" aria-label="Permalink to &quot;**刷入大功率immortalwrt固件**&quot;">​</a></h3><p>OpenWrt固件采用237176253大佬的闭源大功率固件，</p><p><img src="https://pica.zhimg.com/v2-5463ae3cd34c9ebc7855256c93ed455a_1440w.jpg" alt=""> ▲ 电脑浏览器输入：192.168.1.1 进入uboot界面，选择下载好的的<code>immortalwrt-mediatek- mt7986-netcore_n60-pro-squashfs-sysupgrade.bin</code>固件，上传刷入固件即可。</p><h3 id="恢复官方固件" tabindex="-1"><strong>恢复官方固件</strong> <a class="header-anchor" href="#恢复官方固件" aria-label="Permalink to &quot;**恢复官方固件**&quot;">​</a></h3><p><img src="https://pica.zhimg.com/v2-d606f1d61096722fec9c8c6967a36e98_1440w.jpg" alt=""></p><p>如果需要恢复原厂固件，进入uboot后选择之前备份的<code>mtd5_ubi.bin</code>文件刷入即可。</p><h3 id="_5g无线信号测试" tabindex="-1"><strong>5G无线信号测试</strong> <a class="header-anchor" href="#_5g无线信号测试" aria-label="Permalink to &quot;**5G无线信号测试**&quot;">​</a></h3><p>采用自建speedtest服务，测试户型如图，路由器放置客厅角落弱电箱旁，测试穿墙效果如何</p><p><img src="https://pic3.zhimg.com/v2-1c100f102fd8b00e0e5bd1512850885e_1440w.jpg" alt=""> ▲ 主卧靠墙角与路由器所在位置有两面墙、有部分是承重墙体比较厚，信号衰减的很严重，难度比较大</p><p><img src="https://pic1.zhimg.com/v2-77f2576f189a51fc2e701138f74304e6_1440w.jpg" alt=""> ▲ 近距离和中距离都很稳定能跑满千兆带宽，死角位置大功率固件有一定的提升、但不多。</p><h3 id="immortalwrt系统" tabindex="-1"><strong>immortalwrt系统</strong> <a class="header-anchor" href="#immortalwrt系统" aria-label="Permalink to &quot;**immortalwrt系统**&quot;">​</a></h3><p>默认IP：192.168.6.1 用户名：root 密码无</p><p><img src="https://pic1.zhimg.com/v2-0663a56151f628eca9ca635933ac20b8_1440w.jpg" alt=""> ▲ immortalwrt固件大家很熟悉了，剩下的可以随便折腾了、这个固件支持USB上网，插入手机或者上网卡后新建一个接口，设置下即可。</p><h3 id="fast网速测试" tabindex="-1"><strong>FAST网速测试</strong> <a class="header-anchor" href="#fast网速测试" aria-label="Permalink to &quot;**FAST网速测试**&quot;">​</a></h3><p><img src="https://pica.zhimg.com/v2-105ce086a3caf7ae2f99c578144fe902_1440w.jpg" alt=""> ▲ FAST测速在800到900Mbps之间，属于MT7986A处理器正常水平，接近跑满千兆带宽了。</p><h3 id="smb网络共享" tabindex="-1"><strong>SMB网络共享</strong> <a class="header-anchor" href="#smb网络共享" aria-label="Permalink to &quot;**SMB网络共享**&quot;">​</a></h3><p>来到服务→网络共享，</p><p><img src="https://pic3.zhimg.com/v2-d203d0a95413be0fa68c65fdb4341cb4_1440w.jpg" alt=""> ▲ 名称随意，路径在挂载点查看挂载的路径，一般是<code>/mnt/sda1</code>，点击保存并应用。</p><p>这一步开启了smb共享文件，Mac电脑可以直接前往服务器，输入路由器IP，选择客人模式即可访问文件夹，Win系统默认不允许匿名访问共享文件夹，我们需要创建一个用户。</p><p><strong>SSH连接路由器，Ksmbd进行共享，添加用户和密码的步骤如下：</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ksmbd.adduser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>统会提示输入密码。输入密码时，终端不会显示任何字符，这是正常现象,输入密码后，再次确认密码。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/init.d/ksmbd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>重启一下ksmbd服务</li></ul><p>进入我的电脑输入<code>\\\\192.168.6.1</code>，输入用户名和密码，即可连接。</p><p><img src="https://picx.zhimg.com/v2-6c5287e73809130e398200d5779a3a93_1440w.jpg" alt=""> ▲ 这次读写速度比官方固件快多了，拖动文件读取速度大概100MB左右，略微超越了千兆带宽，写入速度70MB左右。</p><h3 id="安装istore商店" tabindex="-1"><strong>安装istore商店</strong> <a class="header-anchor" href="#安装istore商店" aria-label="Permalink to &quot;**安装istore商店**&quot;">​</a></h3><p>为了方便我们安装插件，推荐安装一个istore商店，里面有很多实用的插件方便使用，</p><p><img src="https://pic2.zhimg.com/v2-d866306a874c7bb8dc10a5c8fd8a20cd_1440w.jpg" alt=""> ▲ 刚刷好系统剩余的软件包空间还有64MB，虽然不多，装7个左右常用的插件是够了的</p><p>SSH连接路由器后，逐条输入下面代码：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opkg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> exit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/linkease/openwrt-app-actions/raw/main/applications/luci-app-systools/root/usr/share/systools/istore-reinstall.run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> istore-reinstall.run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./istore-reinstall.run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>有报错也没有关系，安装完成后退出登录、重新进入后台，就有istore商店了</p><p><img src="https://pic2.zhimg.com/v2-44275872d16630b0c41fb2512ba3729d_1440w.jpg" alt=""> ▲ 我安装了几款插件后还剩余40MB左右的空间。</p><h3 id="功耗" tabindex="-1"><strong>功耗</strong> <a class="header-anchor" href="#功耗" aria-label="Permalink to &quot;**功耗**&quot;">​</a></h3><p><img src="https://pic3.zhimg.com/v2-42217e125907146715f64ff9728fd268_1440w.jpg" alt=""> ▲ 没有插入USB硬盘，待机功耗6W左右，算是比较低。</p><h3 id="总结" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;**总结**&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>磊科N60PRO的双2.5G网口+512MB大内存在WiFi7时代也够用了，是一个一步到位的性价比之选，还有这个价位少见的USB3.0接口，给路由器可玩性上升了一个台阶，官方固件虽然功能有限，但我们刷入OpenWrt系统后，直接起飞~</p></div>`,65)),i(t),i(e)])}const F=n(o,[["render",h]]);export{u as __pageData,F as default};
